import{_ as t,o,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"13. Consultation","description":"","frontmatter":{"title":"13. Consultation","eba":"Allied Health Professionals 2021-2026","topics":["leave","parental-leave","consultation","union-matters"]},"headers":[],"relativePath":"ebas/allied-health/consultation-disputes/13-consultation.md","filePath":"ebas/allied-health/consultation-disputes/13-consultation.md"}'),r={name:"ebas/allied-health/consultation-disputes/13-consultation.md"};function i(a,e,p,l,h,c){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_13-consultation" tabindex="-1">13. Consultation <a class="header-anchor" href="#_13-consultation" aria-label="Permalink to &quot;13. Consultation&quot;">​</a></h1><p>Nothing in this clause 13 limits the Employer’s obligations to consult with HSRs under the OHS Act.</p><p><strong>13.1</strong> Consultation regarding Major Change</p><p><strong>(a)</strong> Where an Employer proposes a Major Change that may have a Significant Effect on an Employee or Employees, the Employer will consult with the Affected Employee/s, the Union, and the Employee’s other chosen representative (where relevant) through the steps set out below in this clause 13 before the proposed Major Change (including part of a Major Change) occurs.</p><p><strong>(b)</strong> Consultation requires the Employer to take reasonable steps to consult with Employees who are absent on leave including on workers compensation or parental leave.</p><p><strong>(c)</strong> The Employer will take reasonable steps to ensure Employees, HSRs (where relevant) and the Union can participate effectively in the Consultation process.</p><p><strong>(d)</strong> With respect to the process set out in this clause 13:</p><p><strong>(i)</strong> a Major Change (including part of a Major Change) must not be implemented prior to the steps in subclauses 13.4 to 13.9 being completed, other than by agreement with the Affected Employee/s and Union; and</p><p><strong>(ii)</strong> the process in this clause 13 will not be used to prevent or frustrate Major Change, save that a party raising a dispute alleging non-compliance with this clause 13 does not, of itself, indicate the party is trying to prevent or frustrate Major Change.</p><p><strong>(e)</strong> An Employer shall complete each step prior to proceeding to the next step in this process save that nothing prevents an Employer from progressing where the Employer has complied with the relevant requirements of this clause 13 and the Affected Employee/s, the Union, and/or the Employee’s other chosen representative (where relevant) have chosen not to participate / respond, despite being given a reasonable opportunity to do so.</p><p><strong>13.2</strong> Definitions Under this clause 13:</p><p><strong>(a)</strong> Consultation means a genuine opportunity to influence the decision maker, but not joint decision making. It is not merely an announcement as to what is about to happen.</p><p><strong>(b)</strong> Affected Employee means an Employee on whom a major workplace change may have a Significant Effect.</p><p><strong>(c)</strong> Major Change means a change in the Employer’s program, production, organisation (including workforce size), physical workplace, structure, technology, or a change in workplace arrangements (for example, the introduction of an on call roster, after hours or weekend roster, or how work is organised). A Major Change that may have a Significant Effect, regardless of whether it is permanent or temporary requires Consultation under this clause 13.</p><p><strong>(d)</strong> Significant Effect includes but is not limited to:</p><p><strong>(i)</strong> termination of employment;</p><p><strong>(ii)</strong> changes in the size, composition or operation of the Employer’s workforce (including from outsourcing) or skills required;</p><p><strong>(iii)</strong> alteration of the number of hours worked and/or reduction in remuneration;</p><p><strong>(iv)</strong> changes to an Employee’s classification, position description, duties or reporting lines;</p><p><strong>(v)</strong> impacts the workload of the Employee/s;</p><p><strong>(vi)</strong> changes to shifts/rosters, including new shifts / rostering requirements;</p><p><strong>(vii)</strong> the need for retraining or relocation/redeployment/transfer to another site or to other work;</p><p><strong>(viii)</strong> removal of an existing amenity; and/or</p><p><strong>(ix)</strong> the removal or reduction of job opportunities, promotion opportunities or job tenure.</p><p><strong>(e)</strong> Measures to mitigate or avert may include but are not limited to:</p><p><strong>(i)</strong> redeployment;</p><p><strong>(ii)</strong> retraining;</p><p><strong>(iii)</strong> salary maintenance;</p><p><strong>(iv)</strong> job sharing; and/or</p><p><strong>(v)</strong> maintenance of accruals.</p><p><strong>13.3</strong> Consultation Steps and Timeframes</p><p><strong>(a)</strong> Consultation includes the steps set out below.</p><p><strong>(b)</strong> Timeframes for each step must allow a party to Consultation (including a representative) to genuinely participate in an informed way having regard for all the circumstances including the complexity of the change proposed, and the need for Employee/s and their representative to meet with each other and consider and discuss the Employer’s proposal. The timeframes in this subclause</p><p><strong>13.3</strong> are indicative.</p><p><strong>(c)</strong> The following table makes clear the relevant steps and indicative timeframes for the Consultation process.</p><p>Step Action Timeframe</p><ol><li><p>Employer provides Change Impact Statement Starting point of (CIS) and other written material required by consultation subclause 13.4</p></li><li><p>Written response from Employee/s and/or Union 14 days after step 1</p></li><li><p>Consultation Meeting/s convened 7 days to 14 days after step 2 The &#39;first meeting&#39; at step 3 does not limit the number of meetings for Consultation</p></li><li><p>Further Employer response (where relevant) After the conclusion of step 3</p></li><li><p>Alternative proposal from Employee/s or Union 14 days after step 4</p></li><li><p>Employer to consider alternative proposal/s 14 days after step 5 consistent with the obligation to consult and, if applicable, to arrange further meetings with Employee/s or Union prior to advising outcome of Consultation</p></li></ol><p><strong>13.4</strong> Change Impact Statement (CIS) (Step 1)</p><p><strong>(a)</strong> Prior to Consultation required by this clause 13, the Employer will provide Affected Employee/s and Union with a written Change Impact Statement (CIS) setting out all relevant information including:</p><p><strong>(i)</strong> the details of proposed change;</p><p><strong>(ii)</strong> the reasons for the proposed change;</p><p><strong>(iii)</strong> where relevant, the current position descriptions of positions that may be affected by the proposed change;</p><p><strong>(iv)</strong> any proposed new or revised position descriptions;</p><p><strong>(v)</strong> the possible effect of the proposed change on Affected Employee/s workload;</p><p><strong>(vi)</strong> where there may be occupational health and safety impacts a risk assessment of the potential effects of the change on the health and safety of Affected Employee/s and any other occupational health and safety impacts, such as those set out in <a href="/eba/ebas/allied-health/ohs/99-ohs-risk-management.html">clause 99</a> (OHS Risk Management), which must be undertaken in Consultation with HSRs, and the proposed mitigating actions to be implemented to prevent such effects;</p><p><strong>(vii)</strong> the expected benefit of the change;</p><p><strong>(viii)</strong> measures the Employer is considering that may mitigate or avert the effects of the proposed change;</p><p><strong>(ix)</strong> the right of an Affected Employee/s to have a representative including a Union representative at any time during the change process; and</p><p><strong>(x)</strong> other written material relevant to the reasons for the proposed change (such as consultant reports), excluding material that is commercial in confidence, relates directly to a performance/conduct issue or cannot be disclosed under the Health Services Act 1988 (Vic) or other legislation.</p><p><strong>(b)</strong> Concerns as to whether the Change Impact Statement (CIS) complies with subclause 13.4 will be raised as soon as reasonably practicable, which may be at a time after step 2 has been completed.</p><p><strong>(c)</strong> Where the Union requests a meeting prior to the step 2 to clarify the proposed change or to obtain any of the information required to be provided as part of step 1 or step 2, the Employer will meet with the Union in a reasonable timeframe.</p><p><strong>13.5</strong> Employee / Union response (step 2) Following receipt of the Change Impact Statement (CIS), Affected Employee/s and/or the Union may respond in writing to any matter arising from the proposed change.</p><p><strong>13.6</strong> Meetings (step 3)</p><p><strong>(a)</strong> As part of Consultation, the Employer will meet with the Affected Employee/s, the Union and other nominated representative/s (if any) to discuss:</p><p><strong>(i)</strong> the proposed change;</p><p><strong>(ii)</strong> proposals to mitigate or avert the impact of the proposed change; and</p><p><strong>(iii)</strong> any matter identified in the written response from the Affected Employee/s and/or the Union.</p><p><strong>(b)</strong> To avoid doubt, the ‘first meeting’ at step 3 does not limit the number of meetings for Consultation.</p><p><strong>13.7</strong> Employer response (step 4) The Employer will give prompt and genuine consideration to matters arising from Consultation and will provide a written response to the matters raised by the Affected Employee/s, Union and (where relevant) other representative/s.</p><p><strong>13.8</strong> Alternative proposal (step 5) The Affected Employee/s, the Union and other representative (where relevant) may submit alternative proposal/s which will take into account the intended objective and benefits of the proposal. Alternative proposals should be submitted in a timely manner so that unreasonable delay may be avoided.</p><p><strong>13.9</strong> Outcome of Consultation (step 6)</p><p><strong>(a)</strong> The Employer will give prompt and genuine consideration to matters arising from Consultation, including an alternative proposal submitted under subclause 13.8,</p><p>and will advise the Affected Employee/s, the Union and other nominated representatives (if any) in writing of the outcome of Consultation including:</p><p><strong>(i)</strong> whether the Employer intends to proceed with the change proposal and, if so, when, which shall not be less than seven (7) days from the date of the written advice;</p><p><strong>(ii)</strong> any amendment to the change proposal arising from Consultation;</p><p><strong>(iii)</strong> details of any measures to mitigate or avert the effect of the changes on Affected Employee/s; and</p><p><strong>(iv)</strong> a summary of how matters that have been raised by Affected Employee/s, the Union and their representatives, including any alternative proposal, have been taken into account.</p><p><strong>(b)</strong> Where a party notifies or escalates a dispute (including to the Commission) within seven (7) days of the written advice, subclause 13.10(b) applies.</p><p><strong>13.10</strong> Consultation disputes</p><p><strong>(a)</strong> Any dispute regarding the obligations under this clause 13 will be dealt with under the Dispute Resolution Procedure at <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> of this Agreement.</p><p><strong>(b)</strong> Where a consultation dispute is raised in accordance with <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> of the Agreement, the obligations at subclause 14.2 apply including:</p><p><strong>(i)</strong> the parties to the dispute and their representatives must genuinely attempt to resolve the dispute through the processes set out in <a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a> and must cooperate to ensure that these processes are carried out expeditiously; and</p><p><strong>(ii)</strong> while the dispute resolution procedure is being conducted work will continue normally according to the usual practice that existed before the dispute, until the dispute is resolved (meaning the Major Change is not to be implemented while the dispute is unresolved, subject to subclause 13.10(d)).</p><p><strong>(c)</strong> Where an Employer has implemented a change and a dispute is notified alleging the Employer’s failure to consult in accordance with clause 13, the Employer will reverse the change and restore the status quo that existed before the change was implemented, except where:</p><p><strong>(i)</strong> the Employer: A. disputes the alleged failure to consult in accordance with clause 13; and B. makes an application to the Commission in accordance with subclause 13.10(d) within seven (7) days of the dispute being notified;</p><p><strong>(ii)</strong> in which case the requirement to reverse the change does not apply until the matter is dealt with under subclause 13.10(d); or</p><p><strong>(iii)</strong> the Employer has completed step 6 of the consultation process and issued the written notification in subclause 13.9(a) and the Affected</p><p>Employee/s, the Union, and/or the Employee’s other chosen representative (where relevant) have not notified or escalated a dispute (including to the Commission) within seven (7) days of this written notification; or</p><p><strong>(iv)</strong> the Affected Employee/s and the Union agree in writing the change is not required to be reversed.</p><p><strong>(d)</strong> A party may seek an interim decision or, by agreement with the parties to the dispute, a recommendation of the Commission, in accordance with subclause 14.2(e), including where an Employer has made an application referred to in subclause 13.10(c)(i) regarding the reversal of an implemented Major Change (in whole or part) while the dispute is being resolved. The Commission may consider:</p><p><strong>(i)</strong> the impact of reversing and not reversing the change on the Employer and Affected Employees;</p><p><strong>(ii)</strong> whether the Employer has complied with the steps at subclauses 13.4 to</p><p><strong>13.9</strong> of this Agreement;</p><p><strong>(iii)</strong> whether a party to the dispute has complied with subclause 14.2; and</p><p><strong>(iv)</strong> any other matter the Commission considers relevant. Consult ation about Ch ang es to Ro ster s o r Hour s of Work</p><p>Plain language terms: consult, major workplace change.</p>',86)])])}const u=t(r,[["render",i]]);export{d as __pageData,u as default};
